mapper.select:
SELECT TIME as time, DEV_NAME as devName,UTILIZATION as utilization,SIZE as size,IO_STAT as ioStat,RD_STAT as rdStat,WR_STAT as wrStat, RD_REQ as rdReq,WR_REQ as wrReq,RD_REQ_PS as rdReqps,WR_REQ_PS as wrReqps, RD_LATENCY as rdLatency,WR_LATENCY as wrLatency, DOMAIN_ID as domainId, HOST_ID as hostId, HOST_POOL_ID as hostpoolId, CLUSTER_ID as clusterId, OP_GROUP_CODE as operatorGroupCode, OP_GROUP_ID as operatorGroupId FROM TBL_DOMAIN_IO_STAT WHERE TIME BETWEEN ${startTime} AND ${endTime} AND DOMAIN_ID=${domainId}
ORDER BY ${sortField} ASC
ORDER BY ${sortField} DESC

SELECT TIME as time, DEV_NAME as devName,UTILIZATION as utilization,SIZE as size,IO_STAT as ioStat,RD_STAT as rdStat,WR_STAT as wrStat, RD_REQ as rdReq,WR_REQ as wrReq,RD_REQ_PS as rdReqps,WR_REQ_PS as wrReqps, RD_LATENCY as rdLatency,WR_LATENCY as wrLatency FROM TBL_DOMAIN_IO_STAT t WHERE TIME BETWEEN ${startTime} AND ${endTime} AND DOMAIN_ID=${domainId}
AND DEV_NAME = #{currentDisk}
AND DEV_NAME IN (select DEV_NAME from TBL_DOMAIN_IO_STAT t1 WHERE t1.TIME = (select MAX(TIME)-${duration} from TBL_DOMAIN_IO_STAT WHERE DOMAIN_ID=${domainId}) and t1.DOMAIN_ID=${domainId}) ORDER BY TIME ASC

SELECT TIME as time, DEV_NAME as devName,UTILIZATION as utilization,SIZE as size,IO_STAT as ioStat,RD_REQ_PS as rdReqps,
WR_REQ_PS as wrReqps, RD_LATENCY as rdLatency,WR_LATENCY  as wrLatency
FROM TBL_DOMAIN_IO_STAT
WHERE TIME BETWEEN ${startTime} AND ${endTime} AND DOMAIN_ID=${domainId}

    AND DEV_NAME = #{currentDisk}

ORDER BY TIME ASC

SELECT T1.DOMAIN_ID as domain_id, ROUND(T1.IO_STAT,2) as ioStat, T1.TIME as time
FROM TBL_DOMAIN_IO_STAT T1, (SELECT DOMAIN_ID, MAX(TIME) TIME FROM TBL_DOMAIN_IO_STAT WHERE HOST_ID=${hostId} GROUP BY DOMAIN_ID) T2
WHERE T1.DOMAIN_ID = T2.DOMAIN_ID AND T1.TIME = T2.TIME AND T1.HOST_ID=${hostId}

SELECT io.TIME, io.DOMAIN_ID as domainId, io.DEV_NAME as devName, io.UTILIZATION as utilization, io.SIZE as size, io.RD_REQ_PS as rdReqps, io.WR_REQ_PS as wrReqps,
io.IO_STAT as ioStat, io.RD_STAT as rdStat, io.WR_STAT as wrStat, io.RD_REQ as rdReq, io.WR_REQ as wrReq, io.RD_LATENCY as rdLatency, io.WR_LATENCY  as wrLatency
FROM TBL_DOMAIN_IO_STAT io
WHERE io.TIME = (SELECT MAX(TIME)-${duration} FROM TBL_DOMAIN_IO_STAT)

    AND HOST_POOL_ID =${hostPoolId}


    AND CLUSTER_ID =${clusterId}


    AND HOST_ID =${hostId}


    AND DOMAIN_ID = ${domainId}


    AND DOMAIN_ID in (${domainIdList})

SELECT DOMAIN_ID as domainId, ROUND(AVG(IO_STAT),2) as ioStat,ROUND(AVG(RD_STAT),2) as rdStat,
ROUND(AVG(WR_STAT),2) as wrStat,ROUND(AVG(RD_REQ_PS),2) as rdReqps,ROUND(AVG(WR_REQ_PS),2) as wrReqps,DEV_NAME as devName FROM TBL_DOMAIN_IO_STAT
WHERE TIME >= (SELECT MAX(TIME) FROM TBL_DOMAIN_IO_STAT WHERE DOMAIN_ID =  ${domainId}) - ${duration}

    AND DOMAIN_ID = ${domainId}

GROUP BY DOMAIN_ID,DEV_NAME

SELECT stat.DOMAIN_ID as domainId,domain.uuid uuid, domain.title title, domain.host_id hostId,
ROUND(AVG(stat.WR_STAT),2) as wrStat
ROUND(AVG(stat.RD_STAT),2) as rdStat
FROM TBL_DOMAIN_IO_STAT stat , ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_DOMAIN} domain WHERE stat.DOMAIN_ID = domain.id
AND stat.HOST_POOL_ID =${hostPoolId}
AND stat.HOST_ID =${hostId}
AND LOCATE(#{manageExistVm}, domain.metadata)
AND stat.CLUSTER_ID =${clusterId}
AND stat.DOMAIN_ID in (${vmIds})
AND stat.OP_GROUP_CODE LIKE #{operatorGroupCode}
AND stat.TIME BETWEEN ${startTime} AND ${endTime} GROUP BY stat.DOMAIN_ID,domain.uuid, domain.title, domain.host_id HAVING MAX(stat.TIME)> ${endTime} - 241
ORDER BY wrStat DESC
ORDER BY rdStat DESC

SELECT stat.DOMAIN_ID domainId, SUM(stat.rd_avg)+SUM(stat.wr_avg) sumIoStat,
domain.uuid uuid, domain.title title, domain.host_id hostId,domain.cluster_id clusterId,domain.host_pool_id hostPoolId
FROM (SELECT DOMAIN_ID, CEILING(AVG(RD_REQ_PS)) rd_avg, CEILING(AVG(WR_REQ_PS)) wr_avg from TBL_DOMAIN_IO_STAT where
TIME BETWEEN ${startTime} AND ${endTime}

    AND HOST_POOL_ID =${hostPoolId}


    AND DOMAIN_ID IN (${vmIds})


    AND  HOST_ID =${hostId}


    AND CLUSTER_ID =${clusterId}


    AND OP_GROUP_CODE LIKE #{operatorGroupCode}


    AND CLUSTER_ID IN (${clusterIds})


    AND HOST_ID IN (${hostIds})

GROUP BY DOMAIN_ID
HAVING MAX(TIME)> ${endTime} - 241) as stat,
${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_DOMAIN} domain WHERE stat.DOMAIN_ID = domain.id AND domain.enable = 1

    AND LOCATE(#{manageExistVm}, domain.metadata)

GROUP BY stat.DOMAIN_ID,domain.uuid, domain.title, domain.host_id,domain.cluster_id,domain.host_pool_id
ORDER BY  sumIoStat DESC

    LIMIT ${limit}

SELECT tdio.DOMAIN_ID as domainId, SUM(tdio.IO_STAT) as ioStat, tdio.TIME as time, domain.title as title FROM TBL_DOMAIN_IO_STAT tdio INNER JOIN ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_DOMAIN} domain ON tdio.DOMAIN_ID=domain.id WHERE tdio.TIME BETWEEN ${startTime} AND ${endTime}
AND tdio.DOMAIN_ID in (${vmIds})
AND tdio.OP_GROUP_CODE LIKE #{operatorGroupCode}
GROUP BY tdio.DOMAIN_ID, tdio.TIME, domain.title ORDER BY tdio.TIME ASC

SELECT  io.DOMAIN_ID as domainId, io.RD_REQ_PS as rdReqps, io.WR_REQ_PS as wrReqps,
io.RD_LATENCY as rdLatency, io.WR_LATENCY  as wrLatency, io.TIME as time, domain.title as title
FROM TBL_DOMAIN_IO_STAT io INNER JOIN ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_DOMAIN} domain ON io.DOMAIN_ID=domain.id
WHERE io.TIME BETWEEN ${startTime} AND ${endTime}

    AND io.DOMAIN_ID = ${domainId}


    AND io.DEV_NAME = #{currentDisk}


    AND io.OP_GROUP_CODE LIKE #{operatorGroupCode}

ORDER BY io.TIME ASC

SELECT ROUND(AVG(UTILIZATION),2) as avgUtilization, DEV_NAME as devName FROM TBL_DOMAIN_IO_STAT
WHERE TIME BETWEEN ${startTime} AND ${endTime}

    AND DOMAIN_ID = ${domainId}


    AND OP_GROUP_CODE LIKE #{operatorGroupCode}

GROUP BY DEV_NAME

SELECT ROUND(AVG(diskIo.IO_STAT),2) as ioStat, diskIo.TIME as time
FROM TBL_DOMAIN_IO_STAT diskIo, ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_DRX_VM} drxVm
WHERE diskIo.DOMAIN_ID=drxVm.domain_id AND drxVm.drx_business_id=${drxId}
AND diskIo.TIME BETWEEN ${startTime} AND ${endTime}
GROUP BY diskIo.TIME ORDER BY diskIo.TIME ASC

SELECT ROUND(AVG(tts.rate),2) as reqps, tts.TIME as time from(SELECT SUM(iostat.RD_REQ_PS)+SUM(iostat.WR_REQ_PS) rate,iostat.TIME
FROM TBL_DOMAIN_IO_STAT iostat,${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_DRX_VM}  drxVm
WHERE iostat.DOMAIN_ID=drxVm.domain_id AND drxVm.drx_business_id=${drxId}
AND iostat.TIME BETWEEN ${startTime} AND ${endTime}
GROUP BY iostat.TIME,iostat.DOMAIN_ID )tts GROUP BY tts.TIME ORDER BY tts.TIME ASC

SELECT DOMAIN_ID as domainId, DEV_NAME as devName,
ROUND(AVG(UTILIZATION),2) as avgUtilization, MAX(UTILIZATION) as maxUtilization, MIN(UTILIZATION) as minUtilization
FROM TBL_DOMAIN_IO_STAT detail WHERE TIME BETWEEN ${startTime} AND ${endTime}

    AND DOMAIN_ID = ${domainId}


    AND DOMAIN_ID in (${vmIds})

GROUP BY DOMAIN_ID, DEV_NAME
